// C2: Acting Components
instance MotorController : DTDFVocab:ActingComponent [
    base:desc "Electronic speed controller (Vedder Electronic) that converts desired speed commands into motor voltage signals for the autonomous vehicle's propulsion system."
]

instance SteeringServo : DTDFVocab:ActingComponent [
    base:desc "High-precision servo mechanism controlled via ActuationFunctionalEntity that adjusts the vehicle's steering angle based on processed path commands."
]

// C3: Physical Sensing Components
instance LidarSensor : DTDFVocab:SensingComponent [
    base:desc "Hokuyo UST-10LX LiDAR providing 3D point cloud data for object detection and environmental mapping at 10Hz."
    DTDFVocab:producedData LidarPointCloudData
]

instance DepthCamera : DTDFVocab:SensingComponent [
    base:desc "Intel Deepsense D435i RGB-D camera capturing visual data and depth information for environmental perception."
    DTDFVocab:producedData CameraVisualData
]

instance SpeedSensor : DTDFVocab:SensingComponent [
    base:desc "Vehicle speed sensor providing real-time ego vehicle velocity data for state estimation."
    DTDFVocab:producedData VehicleSpeedData
]

instance SteeringAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Steering angle sensor measuring the current steering position of the autonomous vehicle."
    DTDFVocab:producedData SteeringAngleData
]

// C4: Physical-to-Virtual Interaction
instance LidarPointCloudData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom LidarSensor
]

instance CameraVisualData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom DepthCamera
]

instance VehicleSpeedData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SpeedSensor
]

instance SteeringAngleData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SteeringAngleSensor
]

// C10: Models/Data
instance DBSCANClusteringModel : DTDFVocab:Model [
    base:desc "DBSCAN algorithm implementation for point cloud clustering to identify and segment objects in the vehicle's environment."
    DTDFVocab:inputTo PointCloudProcessingEnabler
]

instance KalmanTrackingModel : DTDFVocab:Model [
    base:desc "Kalman filter implementation for tracking detected objects and estimating their trajectories based on sensor data."
    DTDFVocab:inputTo TrackingEnabler
]

instance ACCControlLogic : DTDFVocab:Model [
    base:desc "ISO 15622-compliant Adaptive Cruise Control logic that processes object tracks and vehicle state to determine appropriate speed adjustments."
    DTDFVocab:inputTo ControlEnabler
]

instance VehicleStateDatabase : DTDFVocab:Data [
    base:desc "SQL database storing historical and real-time vehicle state data including speed, steering angle, and environmental conditions."
    DTDFVocab:fromData VehicleStateDataTransmitted
]

instance ObjectTrackDatabase : DTDFVocab:Data [
    base:desc "SQL database storing processed object tracks and trajectories generated from sensor data."
    DTDFVocab:fromData ObjectTrackDataTransmitted
]

instance VehicleStateDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleSpeedData, SteeringAngleData
]

instance ObjectTrackDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom PointCloudProcessingEnabler, TrackingEnabler
]

// C11: Enablers
instance PointCloudProcessingEnabler : DTDFVocab:Enabler [
    base:desc "NVIDIA Jetpack 5.0 SDK and MATLAB/Simulink environment for processing LiDAR point cloud data using DBSCAN clustering."
    DTDFVocab:enables PointCloudClusteringService
]

instance TrackingEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 middleware and Python 3.8 implementation of Kalman filter for object tracking and trajectory prediction."
    DTDFVocab:enables ObjectTrackingService
]

instance ControlEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 packages implementing ISO 23247 Functional Entities for ACC control logic execution."
    DTDFVocab:enables AdaptiveCruiseControlService
]

instance DatabaseEnabler : DTDFVocab:Enabler [
    base:desc "SQL database management system for storing and querying vehicle state and object track data."
    DTDFVocab:enables DataMonitoringService
]

instance VisualizationEnabler : DTDFVocab:Enabler [
    base:desc "ROS2-based visualization tools for real-time display of vehicle state, object tracks, and projected paths."
    DTDFVocab:enables RealTimeVisualizationService
]

// C6: Services
instance PointCloudClusteringService : DTDFVocab:Service [
    base:desc "Service that processes raw LiDAR point cloud data to identify and cluster objects in the vehicle's environment."
    DTDFVocab:provides ObjectDetectionInsight
]

instance ObjectTrackingService : DTDFVocab:Service [
    base:desc "Service that tracks detected objects and predicts their future trajectories using Kalman filtering."
    DTDFVocab:provides ObjectTrackInsight
]

instance AdaptiveCruiseControlService : DTDFVocab:Service [
    base:desc "Service that implements ISO 15622 compliant ACC logic to adjust vehicle speed based on object tracks and desired speed settings."
    DTDFVocab:provides SpeedAdjustmentAction, EmergencyBrakingAction
]

instance DataMonitoringService : DTDFVocab:Service [
    base:desc "Service that monitors and stores vehicle state data and object tracks in the SQL database."
    DTDFVocab:provides VehicleStateInsight
]

instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Service that provides real-time visualization of vehicle state, object tracks, and projected paths via UI."
    DTDFVocab:provides VisualizationInsight
]

// C17: Insights/Actions
instance ObjectDetectionInsight : DTDFVocab:Insight [
    base:desc "Real-time detection and clustering of objects in the vehicle's environment using DBSCAN algorithm."
]

instance ObjectTrackInsight : DTDFVocab:Insight [
    base:desc "Predicted trajectories and current positions of detected objects in the vehicle's path."
]

instance VehicleStateInsight : DTDFVocab:Insight [
    base:desc "Real-time vehicle state data including speed, steering angle, and environmental conditions."
]

instance VisualizationInsight : DTDFVocab:Insight [
    base:desc "Graphical representation of vehicle state, object tracks, and projected path for operator monitoring."
]

instance SpeedAdjustmentAction : DTDFVocab:Action [
    base:desc "Adjusts vehicle speed according to ACC control logic based on object proximity and desired speed settings."
    DTDFVocab:IsAutomatic true
]

instance EmergencyBrakingAction : DTDFVocab:Action [
    base:desc "Instantaneous braking activation triggered by critical object detection or operator command."
    DTDFVocab:IsAutomatic false
]

// C1: System Under Study
instance AutonomousVehicle : DTDFVocab:Environment [
    base:desc "1/10th-scale autonomous vehicle retrofitted from Traxxas Slash 4x4 Premium with NVIDIA Jetson NX/Orin Nano microcomputers."
    base:contains VehicleHardwarePlatform, SoftwarePlatform
]

instance VehicleHardwarePlatform : DTDFVocab:Component [
    base:desc "Physical hardware platform including NVIDIA Jetson NX/Orin Nano, Hokuyo UST-10LX LiDAR, Intel Deepsense D435i camera, and Vedder Electronic Speed Controller."
    base:isContainedIn AutonomousVehicle
]

instance SoftwarePlatform : DTDFVocab:Component [
    base:desc "ROS2 middleware stack with Python 3.8 and C++ implementations for perception, control, and visualization."
    base:isContainedIn AutonomousVehicle
]

// C12: Functional Entities (ISO 23247)
instance PerceptionFunctionalEntity : DTDFVocab:Component [
    base:desc "ROS2 package implementing ISO 23247 Perception Functional Entity for sensor data processing and object detection."
    base:isContainedIn VehicleEntity
    DTDFVocab:inputTo PointCloudProcessingEnabler, TrackingEnabler
]

instance ControlFunctionalEntity : DTDFVocab:Component [
    base:desc "ROS2 package implementing ISO 23247 Control Functional Entity for ACC logic execution and actuation commands."
    base:isContainedIn VehicleEntity
    DTDFVocab:inputTo ControlEnabler
]

instance ActuationFunctionalEntity : DTDFVocab:Component [
    base:desc "ROS2 package implementing ISO 23247 Actuation Functional Entity that converts control commands into motor and steering signals."
    base:isContainedIn VehicleEntity
    DTDFVocab:enables SpeedAdjustmentAction, EmergencyBrakingAction
]

// C13: Deployment Entities
instance VehicleEntity : DTDFVocab:Component [
    base:desc "Physical Twin Entity deployed on the autonomous vehicle hardware platform executing perception and control tasks."
    base:isContainedIn AutonomousVehicle
    base:contains PerceptionFunctionalEntity, ControlFunctionalEntity, ActuationFunctionalEntity
]

instance CloudEntity : DTDFVocab:Component [
    base:desc "Digital Twin Entity deployed in cloud infrastructure for data storage, advanced analytics, and remote management."
    base:isContainedIn AutonomousVehicleSystem
    base:contains DatabaseEnabler, VisualizationEnabler
]

instance UserEntity : DTDFVocab:Component [
    base:desc "User interface entity providing remote management capabilities including ACC enable/disable and emergency braking."
    base:isContainedIn AutonomousVehicleSystem
    DTDFVocab:inputTo EmergencyBrakingAction
]

instance AutonomousVehicleSystem : DTDFVocab:Environment [
    base:desc "System under study for the autonomous vehicle twinning process."
    DTDFVocab:hasEnvironment AutonomousVehicle
    base:contains VehicleEntity, CloudEntity, UserEntity
]

